#include <cstdint>
#include <cstddef>

int64_t process_array_scalar(const int32_t* data, size_t n)
{
 int64_t sum = 0;

 for (size_t i = 0; i < n; ++i)
 {
 int32_t val = data[i];

 if (val > 0)
 {
 sum += val;
 }
 else if (val < 0)
 {
 sum -= val;
 }
 }

 return sum;
}

#include <iostream>
#include <vector>
#include <chrono>
#include <cassert>
#include "scalar.h"
#include "neon_core.h"

// Объявляем твою функцию-обертку
int64_t process_array_neon(const int32_t* data, size_t n);

int main() {
 const size_t N = 1000000; // 1 миллион элементов для точности замера

 // Используем alignas(16) для эффективной загрузки данных в NEON [cite: 41, 89]
 alignas(16) std::vector<int32_t> data(N);

 // Заполняем массив случайными данными
 for (size_t i = 0; i < N; ++i) {
 data[i] = (rand() % 2000) - 1000; // Числа от -1000 до 999
 }

 // --- Тест Скалярной версии ---
 auto start_s = std::chrono::high_resolution_clock::now();
 int64_t res_scalar = process_array_scalar(data.data(), N);
 auto end_s = std::chrono::high_resolution_clock::now();
 std::chrono::duration<double, std::milli> elapsed_s = end_s - start_s;

 // --- Тест NEON версии ---
 auto start_n = std::chrono::high_resolution_clock::now();
 int64_t res_neon = process_array_neon(data.data(), N);
 auto end_n = std::chrono::high_resolution_clock::now();
 std::chrono::duration<double, std::milli> elapsed_n = end_n - start_n;

 // Проверка корректности (Валидация)
 std::cout << "Scalar Result: " << res_scalar << "\n";
 std::cout << "NEON Result: " << res_neon << "\n";

 if (res_scalar == res_neon) {
 std::cout << "Validation: SUCCESS\n";
 } else {
 std::cerr << "Validation: FAILED!\n";
 return 1;
 }

 // Отчет о производительности
 std::cout << "Scalar Time: " << elapsed_s.count() << " ms\n";
 std::cout << "NEON Time: " << elapsed_n.count() << " ms\n";
 std::cout << "Speedup: " << (elapsed_s.count() / elapsed_n.count()) << "x\n";

 return 0;
}

#include "neon_core.h"
#include <arm_neon.h>
#include <cstdint>
#include <cstddef>

int64_t process_array_neon(const int32_t* data, size_t n) {
 int64_t sum = 0;
 // Инициализируем векторный аккумулятор нулями [cite: 53]
 int32x4_t acc = vdupq_n_s32(0); 

 size_t i = 0;
 // Основной цикл: обрабатываем по 4 элемента за раз [cite: 55]
 for (; i + 3 < n; i += 4) {
 // Вызываем функцию Человека 2 и прибавляем результат к аккумулятору
 int32x4_t res = neon_process_chunk(data + i);
 acc = vaddq_s32(acc, res); 
 }

 // Горизонтальное сложение: схлопываем 4 частичные суммы в одну [cite: 45, 71]
 // Примечание: vaddlvq_s32 доступна на ARMv8-A (64-бит) [cite: 74]
 sum = vaddlvq_s32(acc); 

 // Обработка остатка (хвоста): от 0 до 3 элементов [cite: 72, 73]
 for (; i < n; ++i) {
 int32_t val = data[i];
 if (val > 0) sum += val;
 else if (val < 0) sum -= val; // Модуль для отрицательных [cite: 78, 79]
 }

 return sum;
}

#include <arm_neon.h>
#include <cstdint>

int32x4_t neon_process_chunk(const int32_t* data) {
 int32x4_t vec = vld1q_s32(data);

 int32x4_t zero = vdupq_n_s32(0);

 int32x4_t mask_pos = vcgtq_s32(vec, zero);
 int32x4_t mask_neg = vcltq_s32(vec, zero);

 int32x4_t sign = vshrq_n_s32(vec, 31);

 int32x4_t abs_vec = veorq_s32(vec, sign);
 abs_vec = vsubq_s32(abs_vec, sign);

 int32x4_t pos_part = vandq_s32(vec, mask_pos);

 int32x4_t neg_part = vandq_s32(abs_vec, mask_neg);

 int32x4_t result = vorrq_s32(pos_part, neg_part);

 return result;
}

